<?php $pageTitle='إعدادات الموقع'; include __DIR__.'/includes/header.php'; $pdo=getDB(); $msg='';
if($_SERVER['REQUEST_METHOD']==='POST' && adminTableExists($pdo,'settings')){foreach($_POST['settings'] as $k=>$v){$pdo->prepare('INSERT INTO settings (setting_key,setting_value,type) VALUES (?,?,"text") ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)')->execute([$k,trim($v)]);} $msg='تم حفظ الإعدادات';}
$defaults=['site_name_ar'=>'ORCA','site_name_en'=>'ORCA Truck Parts','contact_email'=>'info@example.com','contact_phone'=>'+000'];
$rows=adminTableExists($pdo,'settings')?adminFetchAll($pdo,'SELECT setting_key,setting_value FROM settings'):[]; foreach($rows as $r){$defaults[$r['setting_key']]=$r['setting_value'];}
?>
<div class="container-fluid"><h1 class="h4">إعدادات عامة + مكان الشعار</h1><?php if($msg):?><div class="alert alert-success"><?php echo $msg;?></div><?php endif;?><form method="post" class="card card-body"><label class="form-label">اسم الموقع AR</label><input class="form-control mb-2" name="settings[site_name_ar]" value="<?php echo escape($defaults['site_name_ar']);?>"><label class="form-label">اسم الموقع EN</label><input class="form-control mb-2" name="settings[site_name_en]" value="<?php echo escape($defaults['site_name_en']);?>"><label class="form-label">البريد</label><input class="form-control mb-2" name="settings[contact_email]" value="<?php echo escape($defaults['contact_email']);?>"><label class="form-label">الهاتف</label><input class="form-control mb-2" name="settings[contact_phone]" value="<?php echo escape($defaults['contact_phone']);?>"><label class="form-label">مسار اللوجو</label><input class="form-control mb-2" name="settings[site_logo]" value="<?php echo escape($defaults['site_logo'] ?? 'assets/images/logo-placeholder.svg');?>"><small class="text-muted">تم إنشاء ملف جاهز للاستبدال: assets/images/logo-placeholder.svg</small><button class="btn btn-primary mt-2">حفظ</button></form></div>
<?php include __DIR__.'/includes/footer.php'; ?>
